// Extrair dados do HTML do email
const htmlContent = $input.item.json.html || $input.item.json.textHtml || '';

// Função para extrair texto entre duas strings
function extractBetween(text, start, end) {
  const startIndex = text.indexOf(start);
  if (startIndex === -1) return '';
  const afterStart = text.substring(startIndex + start.length);
  const endIndex = afterStart.indexOf(end);
  if (endIndex === -1) return afterStart;
  return afterStart.substring(0, endIndex).trim();
}

// 1. Extrair Nome do Aluno
// Entre "Confira a Agenda de" e "e continue acompanhando"
let nomeAluno = extractBetween(htmlContent, 'Confira a Agenda de', 'e continue acompanhando');

// Limpar tags HTML se houver
nomeAluno = nomeAluno.replace(/<[^>]*>/g, '').trim();

// 2. Extrair Conteúdo Principal
// Entre "certo?" e "Confirmar Leitura"
let conteudoPrincipal = extractBetween(htmlContent, 'certo?', 'Confirmar Leitura');

// Limpar tags HTML preservando quebras de linha
conteudoPrincipal = conteudoPrincipal
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<\/p>/gi, '\n')
  .replace(/<[^>]*>/g, '')
  .replace(/&nbsp;/g, ' ')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

// 3. Extrair Links dos Anexos
const linksAnexos = [];

// Procurar por links no HTML
const linkRegex = /<a[^>]*href="([^"]*agendaedu\.com[^"]*)"[^>]*>([^<]*)</gi;
let match;

while ((match = linkRegex.exec(htmlContent)) !== null) {
  const url = match[1];
  const linkText = match[2].trim();

  // Verificar se o texto do link parece ser um nome de arquivo
  if (linkText && (linkText.includes('.pdf') || linkText.includes('.doc') || 
      linkText.includes('.ppt') || linkText.includes('.xls') || 
      linkText.includes('...') || linkText.length > 10)) {
    linksAnexos.push({
      nome: linkText,
      url: url
    });
  }
}

// Retornar os dados extraídos
return {
  json: {
    nomeAluno: nomeAluno,
    conteudoPrincipal: conteudoPrincipal,
    linksAnexos: linksAnexos,
    // Manter dados originais do email
    emailFrom: $input.item.json.from,
    emailSubject: $input.item.json.subject,
    emailDate: $input.item.json.date
  }
};

// Formatar mensagem para WhatsApp
const dados = $input.item.json;

let mensagem = '*Novo Comunicado da Agenda Edu*\n\n';
mensagem += '*Aluno(a):*\n';
mensagem += dados.nomeAluno + '\n\n';
mensagem += '*Atividade:*\n';
mensagem += dados.conteudoPrincipal + '\n\n';

if (dados.linksAnexos && dados.linksAnexos.length > 0) {
  mensagem += '*Links para Anexos:*\n';
  dados.linksAnexos.forEach(link => {
    mensagem += `📎 ${link.nome}\n${link.url}\n\n`;
  });
}

// Criar dois itens de saída, um para cada número de telefone
return [
  {
    json: {
      to: '5521996496442',
      mensagem: mensagem,
      ...dados
    }
  },
  {
    json: {
      to: '5521966719259',
      mensagem: mensagem,
      ...dados
    }
  }
];
